const now = new Date();
const tasks = $input.all().map(item => item.json);

if (tasks.length === 0) {
  return [{ json: { hasTasks: false } }];
}

const overdue = [];
const today = [];
const deadlines = [];
let p1Count = 0;

for (const task of tasks) {
  if (task.priority === 4) p1Count++;

  const dueDate = task.due ? new Date(task.due.date) : null;
  const isOverdue = dueDate && dueDate < new Date(now.toDateString());

  const priorityMap = { 4: 'P1', 3: 'P2', 2: 'P3', 1: 'P4' };
  const pLabel = priorityMap[task.priority] || 'P4';

  const entry = {
    content: task.content,
    priority: pLabel,
    priorityNum: task.priority,
    dueDate: task.due ? task.due.date : null,
    dueString: task.due ? task.due.string : '',
    isRecurring: task.due ? task.due.is_recurring : false,
    projectId: task.project_id,
    labels: task.labels || [],
    deadlineDate: task.deadline ? task.deadline.date : null
  };

  if (isOverdue) {
    const diffMs = now - dueDate;
    entry.daysOverdue = Math.floor(diffMs / (1000 * 60 * 60 * 24));
    overdue.push(entry);
  } else {
    today.push(entry);
  }

  if (task.deadline && task.deadline.date) {
    const dl = new Date(task.deadline.date);
    const daysLeft = Math.ceil((dl - now) / (1000 * 60 * 60 * 24));
    if (daysLeft <= 7) {
      deadlines.push({ content: task.content, deadlineDate: task.deadline.date, daysLeft: daysLeft });
    }
  }
}

overdue.sort((a, b) => b.priorityNum - a.priorityNum || b.daysOverdue - a.daysOverdue);
today.sort((a, b) => b.priorityNum - a.priorityNum);
deadlines.sort((a, b) => a.daysLeft - b.daysLeft);

const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const dateStr = months[now.getMonth()] + ' ' + now.getDate();

let html = '<div style="font-family:-apple-system,BlinkMacSystemFont,sans-serif;max-width:600px;margin:0 auto;color:#1a1a1a;">';
html += '<div style="background:#1a1a1a;color:white;padding:20px;border-radius:8px 8px 0 0;">';
html += '<h1 style="margin:0;font-size:20px;">Daily Briefing \u2014 ' + dateStr + '</h1>';
html += '<p style="margin:5px 0 0;opacity:0.8;font-size:14px;">' + overdue.length + ' overdue \u00b7 ' + today.length + ' today</p>';
html += '</div>';
html += '<div style="padding:20px;background:#f9f9f9;border-radius:0 0 8px 8px;">';

if (overdue.length > 0) {
  html += '<h2 style="color:#dc3545;font-size:16px;margin:0 0 12px;text-transform:uppercase;letter-spacing:1px;">\u26a0 Overdue</h2>';
  html += '<table style="width:100%;border-collapse:collapse;margin-bottom:20px;">';
  for (const t of overdue) {
    const pColor = t.priority === 'P1' ? '#dc3545' : t.priority === 'P2' ? '#fd7e14' : '#6c757d';
    let deadlineNote = '';
    if (t.deadlineDate) {
      const dl = new Date(t.deadlineDate);
      const daysLeft = Math.ceil((dl - now) / (1000 * 60 * 60 * 24));
      deadlineNote = ' <span style="background:#dc3545;color:white;padding:2px 6px;border-radius:3px;font-size:11px;">DEADLINE: ' + t.deadlineDate + ' (' + daysLeft + 'd left)</span>';
    }
    html += '<tr style="border-bottom:1px solid #e9ecef;">';
    html += '<td style="padding:8px 4px;width:40px;"><span style="background:' + pColor + ';color:white;padding:2px 6px;border-radius:3px;font-size:12px;font-weight:bold;">' + t.priority + '</span></td>';
    html += '<td style="padding:8px 4px;">' + t.content + deadlineNote + '</td>';
    html += '<td style="padding:8px 4px;text-align:right;color:#6c757d;font-size:13px;">' + t.daysOverdue + 'd overdue</td>';
    html += '</tr>';
  }
  html += '</table>';
}

if (today.length > 0) {
  html += '<h2 style="color:#28a745;font-size:16px;margin:0 0 12px;text-transform:uppercase;letter-spacing:1px;">\u2713 Today</h2>';
  html += '<table style="width:100%;border-collapse:collapse;margin-bottom:20px;">';
  for (const t of today) {
    const pColor = t.priority === 'P1' ? '#dc3545' : t.priority === 'P2' ? '#fd7e14' : t.priority === 'P3' ? '#ffc107' : '#6c757d';
    html += '<tr style="border-bottom:1px solid #e9ecef;">';
    html += '<td style="padding:8px 4px;width:40px;"><span style="background:' + pColor + ';color:white;padding:2px 6px;border-radius:3px;font-size:12px;font-weight:bold;">' + t.priority + '</span></td>';
    html += '<td style="padding:8px 4px;">' + t.content + '</td>';
    html += '<td style="padding:8px 4px;text-align:right;color:#6c757d;font-size:13px;">' + (t.dueString || '') + '</td>';
    html += '</tr>';
  }
  html += '</table>';
}

if (deadlines.length > 0) {
  html += '<h2 style="color:#6f42c1;font-size:16px;margin:0 0 12px;text-transform:uppercase;letter-spacing:1px;">\ud83c\udfaf Upcoming Deadlines (7 days)</h2>';
  for (const d of deadlines) {
    const urgency = d.daysLeft <= 1 ? '#dc3545' : d.daysLeft <= 3 ? '#fd7e14' : '#6f42c1';
    html += '<p style="margin:4px 0;padding:8px;background:white;border-left:4px solid ' + urgency + ';border-radius:4px;"><strong>' + d.deadlineDate + '</strong> \u2014 ' + d.content + ' <span style="color:' + urgency + ';font-weight:bold;">(' + d.daysLeft + 'd left)</span></p>';
  }
  html += '<br/>';
}

const p1Warning = p1Count > 5 ? '<span style="color:#dc3545;">\u26a0 OVERLOADED \u2014 consider downgrading ' + (p1Count - 5) + '+ tasks</span>' : '<span style="color:#28a745;">\u2713 Healthy</span>';
html += '<div style="background:white;padding:12px;border-radius:6px;margin-top:8px;">';
html += '<strong>P1 Health:</strong> ' + p1Count + ' active \u2014 ' + p1Warning;
html += '</div></div></div>';

const subject = '[Daily Briefing] ' + dateStr + ' \u2014 ' + overdue.length + ' overdue, ' + today.length + ' today';

return [{ json: { hasTasks: true, subject: subject, html: html, overdueCount: overdue.length, todayCount: today.length, p1Count: p1Count } }];
